//      outputs.table = 'sc_task';
//      outputs.record_id = gr.insert();
//
//      // Test step 2 - access added data and validate
//      // check that the record exists (or that business logic changed it)
//      var gr = new GlideRecord("sc_task");
//      gr.get(steps(PREVIOUS_STEP_SYS_ID).record_id);
//      assertEqual({name: "task gr exists", shouldbe: true, value: gr.isValidRecord()});
//
//
// stepResult.setOutputMessage: Log a message to step results after step executes.
//                              Can only be called once or will overwrite previous
//                              message
//
//  Example:
//
//      var gr = new GlideRecord('sc_task');
//      gr.setValue('short_description', 'verify task can be inserted');
//      var grSysId = gr.insert();
//      var justCreatedGR = new GlideRecord('sc_task');
//      if (justCreatedGR.get(grSysId)) {
//            stepResult.setOutputMessage("Successfully inserted task record");
//            return true; // pass the step
//      } else {
//            stepResult.setOutputMessage("Failed to insert task record");
//            return false; // fail the step
//      }
//
//
// Note: describe is only supported in Global scope.
// Use 'describe' to create a suite of test scripts and 'it' to define test expectations
//
//  Example jasmine test:
//
//      describe('my suite of script tests', function() {
//            it('should meet expectations', function() {
//                  expect(true).not.toBe(false);
//            });
//      });
//      // make sure to uncomment jasmine.getEnv().execute(); outside the function body
//
//
// assertEqual: A function used to compare that assertion.shouldbe == assertion.value;
//              in case of failure it throws an Error and logs that the assertion by
//              name has failed
//
//  Example:
//
//      var testAssertion = {
//            name: "my test assertion",
//            shouldbe: "expected value"
//            value: "actual value",
//      };
//      assertEqual(testAssertion); // throws Error, logs message to test step output
//
(function (outputs, steps, stepResult, assertEqual) {
	var installedSolutions, performanceEnabledInTanium;
	var tic = new x_taniu_tan_core.TaniumIntegrationCore();
	var performancePropertyEnabled = (gs.getProperty('x_taniu_tan_core.performance_module_enabled', 'true') === 'true');
	try {
		installedSolutions = tic.getInstalledSolutions();
		performanceEnabledInTanium = installedSolutions.Tanium_Performance.installed;
	} catch(ex) {
		stepResult.setOutputMessage(
			'ERROR: Unable to validate whether the Performance module is enabled in your Tanium ' +
			'environment. This may happen if the service account/API token being used to access ' +
			'Tanium does not have sufficient permissions to get this information. Please ' +
			'validate whether the Performance module is installed in your Tanium environment, ' +
			'and set the "x_taniu_tan_core.performance_module_enabled" system property accordingly.'
		);
		return false;
	}
	
	//Check for valid config
	if (performancePropertyEnabled) { //Performance system property is true
		if (performanceEnabledInTanium) { //Performance is installed in Tanium
			//Since performance prop is enabled and performance is installed, log success
			// and return true.
			stepResult.setOutputMessage(
				'Successfully validated. Performance is enabled in Tanium, and system property ' +
				'x_taniu_tan_core.performance_module_enabled is set to true.'
			);
			return true;
		} else {
			//Property is set to true, but Performance module does not appear to be enabled.
			stepResult.setOutputMessage(
				'ERROR: System Property x_taniu_tan_core.performance_module_enabled is set to ' +
				'true, but Performance module does not appear to be enabled in Tanium. This ' +
				'may result in some functionality breaking if it depends on the Tanium ' +
				'Performance module. If this System Property is set to true, Tanium ' +
				'Integration Core will assume that Performance is enabled in Tanium, and ' +
				'will try to call APIs that may rely on the Performance module.'
			);
			return false;
		}
	} else { //Performance system property is set to FALSE
		if (performanceEnabledInTanium) {
			//Property set to false, but Performance IS seemingly enabled in Tanium. Show error.
			stepResult.setOutputMessage(
				'ERROR: System Property x_taniu_tan_core.performance_module_enabled is set to ' +
				'false, but Performance module does appear to be enabled in Tanium. This ' +
				'may result in some unnecessarily limited functionality. If you\'d like to ' +
				'make use of Performance-dependent features from ServiceNow, and if you do ' +
				'indeed have the Performance module licensed and enabled in Tanium, then ' +
				'please set this System Property to TRUE.'
			);
			return false;
		} else {
			//Property is set to false, and Performance is seemingly DISABLED in Tanium.
			// This is a success condition, even though it may result in some functionality
			// being limited.
			stepResult.setOutputMessage(
				'WARNING: Successfully validated - however, Performance does not seem to be ' +
				'enabled in Tanium. System property x_taniu_tan_core.performance_module_enabled ' +
				'is set to false, which is correct and valid; however, please be aware that ' +
				'this will result in some functionality being limited. These limitations are ' +
				'not artificial, but are due to some features of Tanium Integration Core ' +
				'relying on the Tanium Performance module to function. Wherever possible, ' +
				'alternative functionality - while limited - will be used in place of ' +
				'Performance-dependent functionality, but to access the full features of the ' +
				'Tanium Integration Core application, consider talking to your Tanium account ' +
				'manager about purchasing the Performance module.'
			);
			return true;
		}
	}
	
})(outputs, steps, stepResult, assertEqual);
